require("dotenv").config();const express=require("express");const path=require("path");const mysql=require("mysql2/promise");const app=express();const PORT=process.env.PORT||3001;const pool=mysql.createPool({host:process.env.DB_HOST||"localhost",port:process.env.DB_PORT||3306,user:process.env.DB_USER,password:process.env.DB_PASSWORD,database:process.env.DB_NAME,connectionLimit:20,waitForConnections:true});pool.getConnection().then(connection=>{console.log("✅ Connected to MySQL Database:",process.env.DB_NAME);connection.release()}).catch(err=>{console.error("❌ DATABASE CONNECTION FAILED:",err.message)});app.use(express.json());app.use(express.static(path.join(__dirname,"../Client")));app.post("/api/login",async(req,res)=>{try{const{username:username,master_password:master_password}=req.body;console.log("--- Login Attempt ---");console.log("Username provided:",username);console.log("Password provided:",master_password);const[rows]=await pool.query("SELECT id, username FROM users WHERE username = ? AND master_password = ?",[username,master_password]);console.log("Database matches found:",rows.length);if(rows.length>0){res.json({success:true,userId:rows[0].id,user:rows[0].username})}else{res.status(401).json({success:false,message:"Invalid credentials"})}}catch(err){console.error("Login Error:",err);res.status(500).json({error:"Internal Server Error"})}});app.get("/api/user/passwords/all/:userId",async(req,res)=>{try{const{userId:userId}=req.params;const[rows]=await pool.query("SELECT * FROM entries WHERE user_id = ?",[userId]);res.json(rows)}catch(err){console.error(err);res.status(500).json({error:"Could not fetch passwords"})}});app.post("/api/user/passwords",async(req,res)=>{try{const{userId:userId,site:site,username:username,password:password}=req.body;const[result]=await pool.execute("INSERT INTO entries (user_id, site, username, password) VALUES (?, ?, ?, ?)",[userId,site,username,password]);res.status(201).json({success:true,id:result.insertId})}catch(err){console.error("Insert Error:",err);res.status(500).json({error:err.message})}});app.delete("/api/user/passwords/:id",async(req,res)=>{try{await pool.execute("DELETE FROM entries WHERE id = ?",[req.params.id]);res.status(204).send()}catch(err){res.status(500).json({error:"Deletion failure"})}});app.get("/*path",(req,res)=>{if(req.url.startsWith("/api")){console.log("❌ 404 Error: API Route not found:",req.url);return res.status(404).json({error:"API Route not found"})}res.sendFile(path.join(__dirname,"../Client/index.html"))});app.listen(PORT,()=>{console.log(`🚀 Server running on http://localhost:${PORT}`)});